import{_ as t,o,c as s,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"26A. Employment Checks","description":"","frontmatter":{"title":"26A. Employment Checks","eba":"Mental Health Services 2024-2028","topics":["employment","disputes","preliminary","definitions"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/employment-types/26A-employment-checks.md","filePath":"ebas/mental-health/common-terms/employment-types/26A-employment-checks.md"}'),a={name:"ebas/mental-health/common-terms/employment-types/26A-employment-checks.md"};function r(i,e,m,l,c,p){return o(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="_26a-employment-checks" tabindex="-1">26A. Employment Checks <a class="header-anchor" href="#_26a-employment-checks" aria-label="Permalink to &quot;26A. Employment Checks&quot;">​</a></h1><p><strong>26A.1</strong> Definition In this clause, Check means a valid:</p><p><strong>(a)</strong> Police check/ certificate</p><p><strong>(b)</strong> Working with Children Check, and/or</p><p><strong>(c)</strong> NDIS Worker Screening Check.</p><p><strong>26A.2</strong> Requirement to obtain a check</p><p>Where an Employee is required by legislation to possess a Check, it is a condition of the Employee’s employment that they are required to obtain and maintain their own Check. From 1 July 2025, in circumstances where an Employer requires an Employee to possess a Check where it is not required by legislation, the cost shall be borne by the Employer.</p><p><strong>26A.3</strong> Dispute In the event of a dispute as to whether an Employee is required by legislation to possess a Check, it will be resolved in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22</a> (Dispute Resolution Procedure).</p>',8)])])}const y=t(a,[["render",r]]);export{d as __pageData,y as default};
